Here is the standard way to securely load environment variables in a Node.js application.

First, you create a `.env` file in the root of your project:
```env
DB_PASSWORD=super_secret_password_123
```

Then, in your main Node.js file (e.g., `index.js`), you configure `dotenv` at the very top of the file:

```javascript
// Load environment variables immediately
require('dotenv').config();

// Now you can securely access the password via process.env
const dbPassword = process.env.DB_PASSWORD;

if (!dbPassword) {
  console.error('CRITICAL ERROR: DB_PASSWORD is missing in .env file!');
  process.exit(1);
}

// Pass the secure password to your database connection logic
console.log('Database password loaded securely.');
```

The industry standard for basic rate limiting in Express is the `express-rate-limit` package. 

Here is the implementation to restrict IPs to 5 login attempts per 15 minutes:

```javascript
const express = require('express');
const rateLimit = require('express-rate-limit');

const app = express();

// Create the rate limiter middleware
const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // Limit each IP to 5 requests per windowMs
  message: { error: 'Too many login attempts, please try again after 15 minutes' },
  standardHeaders: true,
  legacyHeaders: false,
});

// Apply it strictly to the login route
app.post('/api/login', loginLimiter, (req, res) => {
  // Authentication logic goes here
  res.json({ success: true, token: 'jwt_token_here' });
});

app.listen(3000, () => console.log('Server running on port 3000'));
```

Here is a standard AWS Lambda handler compatible with API Gateway Proxy Integrations. It correctly parses the body and returns the required `statusCode` and `body` string.

```javascript
exports.handler = async (event) => {
  try {
    // API Gateway passes the body as a JSON string
    const body = event.body ? JSON.parse(event.body) : {};
    const name = body.name || 'World';

    const responsePayload = {
      message: `Hello, ${name}!`,
      success: true
    };

    return {
      statusCode: 200,
      headers: {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': '*' // CORS requirement
      },
      body: JSON.stringify(responsePayload)
    };

  } catch (error) {
    console.error('Lambda Execution Error:', error);
    return {
      statusCode: 400,
      body: JSON.stringify({ error: 'Invalid JSON body provided' })
    };
  }
};
```

This is a classic React performance issue. The solution is to wrap the expensive filtering function in the `useMemo` hook so it only recalculates when the actual target data changes, not when unrelated state (like the search input) updates.

Here is how you fix it:

```jsx
import React, { useState, useMemo } from 'react';

export default function Dashboard({ rawData }) {
  const [searchInput, setSearchInput] = useState('');

  // ✅ The expensive operation is now cached. It will only re-run if 'rawData' changes.
  const filteredData = useMemo(() => {
    console.log("Running expensive filter...");
    return rawData.filter(item => item.value > 1000); // Simulated heavy task
  }, [rawData]); 

  return (
    <div>
      <input 
        value={searchInput}
        onChange={(e) => setSearchInput(e.target.value)}
        placeholder="Type something..."
      />
      <ul>
        {filteredData.map(item => <li key={item.id}>{item.name}</li>)}
      </ul>
    </div>
  );
}
```

