Here is a robust Python scraper using `requests` and `BeautifulSoup`. I've included standard headers to prevent basic blocking and used `logging` for output.

```python
import requests
from bs4 import BeautifulSoup
import logging

logging.basicConfig(level=logging.INFO)

def scrape_products(url: str) -> list:
    headers = {'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64)'}

    try:
        response = requests.get(url, headers=headers, timeout=10)
        response.raise_for_status()
    except requests.RequestException as e:
        logging.error(f'Failed to fetch the page: {e}')
        return []

    soup = BeautifulSoup(response.text, 'html.parser')
    products = []

    for item in soup.find_all('div', class_='product-card'):
        title_el = item.find('h2', class_='title')
        price_el = item.find('span', class_='price')

        if title_el and price_el:
            products.append({
                'title': title_el.text.strip(),
                'price': price_el.text.strip()
            })

    logging.info(f'Successfully scraped {len(products)} products.')
    return products

if __name__ == '__main__':
    data = scrape_products('https://example-store.com/products')
```

