Here is a standard, secure JWT verification middleware for Express using the `jsonwebtoken` package:

```javascript
const jwt = require('jsonwebtoken');

function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Extract Bearer token

  if (!token) {
    return res.status(401).json({ error: 'Access denied. No token provided.' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded; // Attach user payload to request
    next(); // Move to the next middleware or route handler
  } catch (error) {
    return res.status(403).json({ error: 'Invalid or expired token.' });
  }
}

module.exports = authenticateToken;
```

The memory leak is happening because the WebSocket connection is not being closed when the component unmounts or re-renders. You need to return a cleanup function from the `useEffect` hook.

Here is the correct implementation:

```jsx
import React, { useEffect, useState } from 'react';

export default function LiveChat() {
  const [messages, setMessages] = useState([]);

  useEffect(() => {
    const ws = new WebSocket('wss://api.example.com/chat');

    ws.onmessage = (event) => {
      setMessages(prev => [...prev, JSON.parse(event.data)]);
    };

    // Cleanup function: closes the connection when the component unmounts
    return () => {
      ws.close();
    };
  }, []); // Empty dependency array ensures it only connects on mount

  return <div>{/* Chat UI */}</div>;
}
```

